"use client";
// Mirrors: include/home_slider.php
import { useState, useEffect } from "react";
const slides = ["/img/intro-carousel/1.jpg", "/img/intro-carousel/2.jpg", "/img/intro-carousel/3.jpg"];
export default function HomeSlider() {
  const [current, setCurrent] = useState(0);
  useEffect(() => {
    const t = setInterval(() => setCurrent((p) => (p + 1) % slides.length), 3000);
    return () => clearInterval(t);
  }, []);
  return (
    <section id="intro">
      <div id="intro-carousel" style={{ width:"100%", height:"500px", backgroundImage:`url('${slides[current]}')`, backgroundSize:"cover", backgroundPosition:"center", transition:"background-image 0.6s ease" }} />
    </section>
  );
}
